from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismSaveSceneVersionNode(BaseNode):
    name = "Prism: Save Scene Version"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("comment", "string", widget_type="text", default="")
        self.add_input("publish", "bool", widget_type="bool", default=False)
        self.add_output("success", "bool")
        self.add_output("saved_path", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        comment = inputs.get('comment') or ''
        publish = bool(inputs.get('publish', False))
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'success': False, 'saved_path': ''}
        try:
            saved = None
            for attr in ('saveSceneVersion', 'saveScene'):
                if hasattr(core, attr):
                    fn = getattr(core, attr)
                    try:
                        saved = fn(comment=comment, publish=publish)
                    except TypeError:
                        saved = fn(comment=comment)
                    break
            if saved is None:
                self.log_error("No saveScene/saveSceneVersion method on this PrismCore.")
                return {'success': False, 'saved_path': ''}
            saved_path = str(saved) if isinstance(saved, (str, bytes)) else ''
            self.log_success(f"Saved scene version: {saved_path or '(ok)'}")
            await self.set_output('exec_out', True)
            return {'success': True, 'saved_path': saved_path}
        except Exception as e:
            self.log_error(f"saveScene failed: {e}")
            return {'success': False, 'saved_path': ''}

def register_node():
    return PrismSaveSceneVersionNode
